def parse_line(line):
    """Parse key=value from a line"""
    match = re.match(r'([^=]+)=(.*)', line)
    if match:
        key = match.group(1).strip().strip("'\"")
        val = match.group(2).strip().strip("'\"")
        return key, val
    return None, None

